    const mainZone = screen.getByTestId("zone-main");
    expect(mainZone).toBeInTheDocument();
    // Session rows should be inside the main zone
    expect(mainZone.querySelectorAll(".srow").length).toBeGreaterThanOrEqual(1);
  });
});

