/**
 * Unit tests: Token Extractor (Step 01-02)
 *
 * Pure function: (payload: unknown) => TokenExtractionResult
 *
 * Properties tested:
 * - Valid payloads always produce 'found' with correct token counts
 * - Cache tokens default to 0 when absent
 * - Payloads without usage field produce 'absent'
 * - Zero tokens are never fabricated from missing data
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import { extractTokenUsage } from "../../../../../src/plugins/norbert-usage/domain/tokenExtractor";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const tokenCountArb = fc.nat({ max: 1_000_000 });
const modelArb = fc.string({ minLength: 1, maxLength: 80 });

const validUsagePayloadArb = fc.record({
  input_tokens: tokenCountArb,
  output_tokens: tokenCountArb,
  model: modelArb,
});

const validUsageWithCacheArb = fc.record({
  input_tokens: tokenCountArb,
  output_tokens: tokenCountArb,
  model: modelArb,
  cache_read_input_tokens: tokenCountArb,
  cache_creation_input_tokens: tokenCountArb,
});

// ---------------------------------------------------------------------------
// PROPERTY: Valid payloads always produce 'found'
// ---------------------------------------------------------------------------

describe("extractTokenUsage with valid usage payloads", () => {
  it("always returns 'found' with matching token counts for any valid payload", () => {
    fc.assert(
      fc.property(validUsagePayloadArb, (usage) => {
        const result = extractTokenUsage({ usage });

        expect(result.tag).toBe("found");
        if (result.tag === "found") {
          expect(result.usage.inputTokens).toBe(usage.input_tokens);
          expect(result.usage.outputTokens).toBe(usage.output_tokens);
          expect(result.usage.model).toBe(usage.model);
        }
      }),
      { numRuns: 200 },
    );
  });

  it("defaults cache tokens to 0 when not present in payload", () => {
    fc.assert(
      fc.property(validUsagePayloadArb, (usage) => {
        const result = extractTokenUsage({ usage });

        expect(result.tag).toBe("found");
        if (result.tag === "found") {
          expect(result.usage.cacheReadTokens).toBe(0);
          expect(result.usage.cacheCreationTokens).toBe(0);
        }
      }),
      { numRuns: 200 },
    );
  });

  it("extracts cache tokens when present in payload", () => {
    fc.assert(
      fc.property(validUsageWithCacheArb, (usage) => {
        const result = extractTokenUsage({ usage });

        expect(result.tag).toBe("found");
        if (result.tag === "found") {
          expect(result.usage.cacheReadTokens).toBe(
            usage.cache_read_input_tokens,
          );
          expect(result.usage.cacheCreationTokens).toBe(
            usage.cache_creation_input_tokens,
          );
        }
      }),
      { numRuns: 200 },
    );
  });
});

// ---------------------------------------------------------------------------
// PROPERTY: Invalid payloads always produce 'absent'
// ---------------------------------------------------------------------------

describe("extractTokenUsage with missing or invalid usage data", () => {
  it("returns 'absent' when payload has no usage field", () => {
    fc.assert(
      fc.property(
        fc.oneof(
          fc.constant({}),
          fc.constant({ other: "data" }),
          fc.record({ name: fc.string() }),
        ),
        (payload) => {
          const result = extractTokenUsage(payload);
          expect(result.tag).toBe("absent");
        },
      ),
      { numRuns: 100 },
    );
  });

  it("returns 'absent' for null and undefined payloads", () => {
    expect(extractTokenUsage(null).tag).toBe("absent");
    expect(extractTokenUsage(undefined).tag).toBe("absent");
  });

  it("returns 'absent' for non-object payloads", () => {
    expect(extractTokenUsage(42).tag).toBe("absent");
    expect(extractTokenUsage("hello").tag).toBe("absent");
    expect(extractTokenUsage(true).tag).toBe("absent");
  });

  it("returns 'absent' when usage exists but required fields are missing", () => {
    // Missing input_tokens
    expect(
      extractTokenUsage({ usage: { output_tokens: 10, model: "m" } }).tag,
    ).toBe("absent");
    // Missing output_tokens
    expect(
      extractTokenUsage({ usage: { input_tokens: 10, model: "m" } }).tag,
    ).toBe("absent");
    // Missing model
    expect(
      extractTokenUsage({ usage: { input_tokens: 10, output_tokens: 10 } }).tag,
    ).toBe("absent");
  });

  it("returns 'absent' when usage fields have wrong types", () => {
    expect(
      extractTokenUsage({
        usage: { input_tokens: "not a number", output_tokens: 10, model: "m" },
      }).tag,
    ).toBe("absent");
    expect(
      extractTokenUsage({
        usage: { input_tokens: 10, output_tokens: "bad", model: "m" },
      }).tag,
    ).toBe("absent");
    expect(
      extractTokenUsage({
        usage: { input_tokens: 10, output_tokens: 10, model: 42 },
      }).tag,
    ).toBe("absent");
  });
});

// ---------------------------------------------------------------------------
// PROPERTY: Zero tokens never fabricated from missing data
// ---------------------------------------------------------------------------

describe("extractTokenUsage never fabricates zero tokens", () => {
  it("absent result has no usage property with zero values", () => {
    const result = extractTokenUsage({ session_id: "s1" });
    expect(result.tag).toBe("absent");
    // The absent variant should NOT have a usage field
    expect("usage" in result).toBe(false);
  });
});

/**
 * Unit tests: Pricing Model (Step 01-03)
 *
 * Pure function: (usage: TokenUsage, table: PricingTable) => CostResult
 *
 * Properties tested:
 * - Total cost equals sum of input, output, and cache costs
 * - All cost components are non-negative for non-negative token counts
 * - Model pattern prefix matching selects correct tier
 * - Unknown models fall back to most expensive (Opus) rates
 * - Zero tokens produce zero cost
 * - Cost scales linearly with token count
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import {
  calculateCost,
  DEFAULT_PRICING_TABLE,
} from "../../../../../src/plugins/norbert-usage/domain/pricingModel";
import type {
  TokenUsage,
  PricingTable,
} from "../../../../../src/plugins/norbert-usage/domain/types";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const tokenCountArb = fc.nat({ max: 1_000_000 });

const opusModelArb = fc.constant("claude-opus-4-20250514");
const sonnetModelArb = fc.constant("claude-sonnet-4-20250514");
const haikuModelArb = fc.constant("claude-haiku-3-5-20241022");
const unknownModelArb = fc.constantFrom(
  "claude-unknown-model-v99",
  "gpt-4o",
  "totally-random-model",
);

const knownModelArb = fc.oneof(opusModelArb, sonnetModelArb, haikuModelArb);

const tokenUsageArb = (modelArb: fc.Arbitrary<string>) =>
  fc.record({
    inputTokens: tokenCountArb,
    outputTokens: tokenCountArb,
    cacheReadTokens: tokenCountArb,
    cacheCreationTokens: tokenCountArb,
    model: modelArb,
  });

// ---------------------------------------------------------------------------
// PROPERTY: Total cost equals sum of components
// ---------------------------------------------------------------------------

describe("calculateCost total equals sum of components", () => {
  it("totalCost always equals inputCost + outputCost + cacheCost", () => {
    fc.assert(
      fc.property(tokenUsageArb(knownModelArb), (usage) => {
        const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

        expect(cost.totalCost).toBeCloseTo(
          cost.inputCost + cost.outputCost + cost.cacheCost,
          10,
        );
      }),
      { numRuns: 500 },
    );
  });
});

// ---------------------------------------------------------------------------
// PROPERTY: All cost components are non-negative
// ---------------------------------------------------------------------------

describe("calculateCost produces non-negative costs", () => {
  it("all cost components are >= 0 for any non-negative token counts", () => {
    fc.assert(
      fc.property(tokenUsageArb(knownModelArb), (usage) => {
        const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

        expect(cost.totalCost).toBeGreaterThanOrEqual(0);
        expect(cost.inputCost).toBeGreaterThanOrEqual(0);
        expect(cost.outputCost).toBeGreaterThanOrEqual(0);
        expect(cost.cacheCost).toBeGreaterThanOrEqual(0);
      }),
      { numRuns: 200 },
    );
  });
});

// ---------------------------------------------------------------------------
// PROPERTY: Zero tokens produce zero cost
// ---------------------------------------------------------------------------

describe("calculateCost with zero tokens", () => {
  it("produces zero cost when all token counts are zero", () => {
    fc.assert(
      fc.property(knownModelArb, (model) => {
        const usage: TokenUsage = {
          inputTokens: 0,
          outputTokens: 0,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          model,
        };
        const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

        expect(cost.totalCost).toBe(0);
        expect(cost.inputCost).toBe(0);
        expect(cost.outputCost).toBe(0);
        expect(cost.cacheCost).toBe(0);
      }),
      { numRuns: 50 },
    );
  });
});

// ---------------------------------------------------------------------------
// PROPERTY: Cost scales linearly with token count
// ---------------------------------------------------------------------------

describe("calculateCost scales linearly", () => {
  it("doubling all token counts doubles the total cost", () => {
    fc.assert(
      fc.property(
        tokenUsageArb(knownModelArb).filter(
          (u) =>
            u.inputTokens > 0 ||
            u.outputTokens > 0 ||
            u.cacheReadTokens > 0 ||
            u.cacheCreationTokens > 0,
        ),
        (usage) => {
          const singleCost = calculateCost(usage, DEFAULT_PRICING_TABLE);
          const doubledUsage: TokenUsage = {
            ...usage,
            inputTokens: usage.inputTokens * 2,
            outputTokens: usage.outputTokens * 2,
            cacheReadTokens: usage.cacheReadTokens * 2,
            cacheCreationTokens: usage.cacheCreationTokens * 2,
          };
          const doubleCost = calculateCost(doubledUsage, DEFAULT_PRICING_TABLE);

          expect(doubleCost.totalCost).toBeCloseTo(
            singleCost.totalCost * 2,
            6,
          );
        },
      ),
      { numRuns: 200 },
    );
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Opus 4 pricing calculation
// ---------------------------------------------------------------------------

describe("calculateCost with Opus 4 model", () => {
  it("computes correct cost for 1200 input and 3400 output tokens", () => {
    const usage: TokenUsage = {
      inputTokens: 1200,
      outputTokens: 3400,
      cacheReadTokens: 0,
      cacheCreationTokens: 0,
      model: "claude-opus-4-20250514",
    };

    const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

    // input: 1200 * $0.015/1k = $0.018
    expect(cost.inputCost).toBeCloseTo(0.018, 4);
    // output: 3400 * $0.075/1k = $0.255
    expect(cost.outputCost).toBeCloseTo(0.255, 4);
    expect(cost.totalCost).toBeCloseTo(0.273, 4);
    expect(cost.model).toBe("claude-opus-4-20250514");
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Sonnet 4 pricing calculation
// ---------------------------------------------------------------------------

describe("calculateCost with Sonnet 4 model", () => {
  it("computes correct cost for 800 input and 2000 output tokens", () => {
    const usage: TokenUsage = {
      inputTokens: 800,
      outputTokens: 2000,
      cacheReadTokens: 0,
      cacheCreationTokens: 0,
      model: "claude-sonnet-4-20250514",
    };

    const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

    // input: 800 * $0.003/1k = $0.0024
    expect(cost.inputCost).toBeCloseTo(0.0024, 4);
    // output: 2000 * $0.015/1k = $0.030
    expect(cost.outputCost).toBeCloseTo(0.03, 4);
    expect(cost.totalCost).toBeCloseTo(0.0324, 4);
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Cache token pricing
// ---------------------------------------------------------------------------

describe("calculateCost with cache tokens", () => {
  it("includes cache read and creation costs at model-specific rates", () => {
    const usage: TokenUsage = {
      inputTokens: 1000,
      outputTokens: 2000,
      cacheReadTokens: 5000,
      cacheCreationTokens: 1000,
      model: "claude-opus-4-20250514",
    };

    const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

    // cache read: 5000 * $0.0015/1k = $0.0075
    // cache creation: 1000 * $0.01875/1k = $0.01875
    expect(cost.cacheCost).toBeCloseTo(0.02625, 4);
    const expectedTotal = 0.015 + 0.15 + 0.0075 + 0.01875;
    expect(cost.totalCost).toBeCloseTo(expectedTotal, 4);
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Unknown model fallback
// ---------------------------------------------------------------------------

describe("calculateCost with unknown model", () => {
  it("falls back to most expensive (Opus) rates for unrecognized models", () => {
    fc.assert(
      fc.property(unknownModelArb, (model) => {
        const usage: TokenUsage = {
          inputTokens: 1000,
          outputTokens: 1000,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          model,
        };

        const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);

        // Opus rates: input $0.015/1k, output $0.075/1k
        expect(cost.inputCost).toBeCloseTo(0.015, 4);
        expect(cost.outputCost).toBeCloseTo(0.075, 4);
        expect(cost.totalCost).toBeCloseTo(0.09, 4);
      }),
      { numRuns: 10 },
    );
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Model preserved in CostResult
// ---------------------------------------------------------------------------

describe("calculateCost preserves model in result", () => {
  it("CostResult.model matches TokenUsage.model", () => {
    fc.assert(
      fc.property(
        tokenUsageArb(fc.oneof(knownModelArb, unknownModelArb)),
        (usage) => {
          const cost = calculateCost(usage, DEFAULT_PRICING_TABLE);
          expect(cost.model).toBe(usage.model);
        },
      ),
      { numRuns: 100 },
    );
  });
});

// ---------------------------------------------------------------------------
// EXAMPLE: Prefix matching selects correct tier
// ---------------------------------------------------------------------------

describe("calculateCost prefix matching", () => {
  it("selects first matching tier by prefix", () => {
    const customTable: PricingTable = [
      {
        modelPattern: "claude-opus",
        inputRate: 0.015,
        outputRate: 0.075,
        cacheReadRate: 0.0015,
        cacheCreationRate: 0.01875,
      },
      {
        modelPattern: "",
        inputRate: 0.001,
        outputRate: 0.005,
        cacheReadRate: 0.0001,
        cacheCreationRate: 0.00125,
      },
    ];

    const opusUsage: TokenUsage = {
      inputTokens: 1000,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheCreationTokens: 0,
      model: "claude-opus-4-20250514",
    };

    const cost = calculateCost(opusUsage, customTable);
    // Matches "claude-opus" prefix -> $0.015/1k
    expect(cost.inputCost).toBeCloseTo(0.015, 4);
  });
});

/**
 * Unit tests: Oscilloscope Stats Bar Formatting (Step 05-02)
 *
 * Pure functions for formatting OscilloscopeStats into display strings:
 * - formatTokenCount: comma-separated integer display
 * - formatWindowDuration: milliseconds to "Xs" display
 * - formatStatsBar: compose stats into display-ready structure
 *
 * Behaviors: 3 (token count formatting, window duration, stats bar composition)
 * Test budget: max 6 tests
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import {
  formatTokenCount,
  formatWindowDuration,
  formatStatsBar,
  type StatsBarDisplay,
} from "../../../../../src/plugins/norbert-usage/domain/oscilloscope";
import type { OscilloscopeStats } from "../../../../../src/plugins/norbert-usage/domain/types";

// ---------------------------------------------------------------------------
// formatTokenCount
// ---------------------------------------------------------------------------

describe("Stats bar token count formatting", () => {
  it("formats integers with comma thousand separators", () => {
    expect(formatTokenCount(0)).toBe("0");
    expect(formatTokenCount(999)).toBe("999");
    expect(formatTokenCount(1000)).toBe("1,000");
    expect(formatTokenCount(87241)).toBe("87,241");
    expect(formatTokenCount(1234567)).toBe("1,234,567");
  });

  it("always produces string without decimals for non-negative integers", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 0, max: 10_000_000 }),
        (count) => {
          const formatted = formatTokenCount(count);
          // Must not contain a decimal point
          expect(formatted).not.toContain(".");
          // Must only contain digits and commas
          expect(formatted).toMatch(/^[\d,]+$/);
        },
      ),
    );
  });
});

// ---------------------------------------------------------------------------
// formatWindowDuration
// ---------------------------------------------------------------------------

describe("Stats bar window duration formatting", () => {
  it("converts milliseconds to seconds display", () => {
    expect(formatWindowDuration(0)).toBe("0s");
    expect(formatWindowDuration(60000)).toBe("60s");
    expect(formatWindowDuration(4000)).toBe("4s");
    expect(formatWindowDuration(59900)).toBe("60s");
  });
});

// ---------------------------------------------------------------------------
// formatStatsBar
// ---------------------------------------------------------------------------

describe("Stats bar composition from OscilloscopeStats", () => {
  it("composes zero stats into all-zero display", () => {
    const zeroStats: OscilloscopeStats = {
      peakRate: 0,
      avgRate: 0,
      totalRateSum: 0,
      windowDuration: 0,
    };

    const display = formatStatsBar(zeroStats);

    expect(display.peakRate).toBe("0 tok/s");
    expect(display.avgRate).toBe("0 tok/s");
    expect(display.totalRateSum).toBe("0");
    expect(display.windowDuration).toBe("0s");
  });

  it("composes non-zero stats into formatted display strings", () => {
    const stats: OscilloscopeStats = {
      peakRate: 512,
      avgRate: 327,
      totalRateSum: 87241,
      windowDuration: 60000,
    };

    const display = formatStatsBar(stats);

    expect(display.peakRate).toBe("512 tok/s");
    expect(display.avgRate).toBe("327 tok/s");
    expect(display.totalRateSum).toBe("87,241");
    expect(display.windowDuration).toBe("60s");
  });
});

/**
 * Unit tests: Gauge Cluster Data Computation (Step 04-01)
 *
 * Pure function: SessionMetrics => GaugeClusterData
 *
 * Properties tested:
 * - Fuel gauge urgency transitions: normal < 70%, amber >= 70%, red >= 90%
 * - Tachometer urgency transitions: normal < 400, amber >= 400, red >= 500
 * - All numeric values are non-negative
 * - Hook health derives from hookEventCount
 * - Zero metrics produce safe defaults
 *
 * Behaviors: 6 (fuel zones, tacho zones, odometer passthrough, rpm passthrough,
 *              warning cluster, zero defaults)
 * Test budget: max 12 tests
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import { createInitialMetrics } from "../../../../../src/plugins/norbert-usage/domain/metricsAggregator";
import type { SessionMetrics } from "../../../../../src/plugins/norbert-usage/domain/types";
import {
  computeGaugeClusterData,
  formatContextTokenLabel,
} from "../../../../../src/plugins/norbert-usage/domain/gaugeCluster";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const sessionMetricsArb = fc.record({
  sessionId: fc.string({ minLength: 1, maxLength: 20 }),
  totalTokens: fc.nat({ max: 1_000_000 }),
  inputTokens: fc.nat({ max: 500_000 }),
  outputTokens: fc.nat({ max: 500_000 }),
  sessionCost: fc.integer({ min: 0, max: 1000 }).map((n) => n / 100),
  toolCallCount: fc.nat({ max: 10_000 }),
  activeAgentCount: fc.nat({ max: 20 }),
  contextWindowPct: fc.integer({ min: 0, max: 100 }),
  contextWindowTokens: fc.nat({ max: 1_000_000 }),
  contextWindowMaxTokens: fc.nat({ max: 1_000_000 }),
  contextWindowModel: fc.string(),
  hookEventCount: fc.nat({ max: 100_000 }),
  sessionStartedAt: fc.constant("2025-01-01T00:00:00Z"),
  lastEventAt: fc.constant("2025-01-01T00:10:00Z"),
  burnRate: fc.integer({ min: 0, max: 2000 }),
});

const createSnapshot = (overrides: Partial<SessionMetrics> = {}): SessionMetrics => ({
  ...createInitialMetrics("test-session"),
  sessionStartedAt: "2025-01-01T00:00:00Z",
  ...overrides,
});

// ---------------------------------------------------------------------------
// Fuel gauge urgency zone transitions
// ---------------------------------------------------------------------------

describe("Fuel gauge urgency zones", () => {
  it("is normal when contextWindowPct < 70", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 0, max: 69 }),
        (pct) => {
          const result = computeGaugeClusterData(createSnapshot({ contextWindowPct: pct }));
          expect(result.fuelGauge.urgency).toBe("normal");
        },
      ),
    );
  });

  it("is amber when contextWindowPct >= 70 and < 90", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 70, max: 89 }),
        (pct) => {
          const result = computeGaugeClusterData(createSnapshot({ contextWindowPct: pct }));
          expect(result.fuelGauge.urgency).toBe("amber");
        },
      ),
    );
  });

  it("is red when contextWindowPct >= 90", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 90, max: 100 }),
        (pct) => {
          const result = computeGaugeClusterData(createSnapshot({ contextWindowPct: pct }));
          expect(result.fuelGauge.urgency).toBe("red");
        },
      ),
    );
  });
});

// ---------------------------------------------------------------------------
// Tachometer urgency zone transitions
// ---------------------------------------------------------------------------

describe("Tachometer urgency zones", () => {
  it("is normal when burnRate < 400", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 0, max: 399 }),
        (rate) => {
          const result = computeGaugeClusterData(createSnapshot({ burnRate: rate }));
          expect(result.tachometer.urgency).toBe("normal");
        },
      ),
    );
  });

  it("is amber when burnRate >= 400 and < 500", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 400, max: 499 }),
        (rate) => {
          const result = computeGaugeClusterData(createSnapshot({ burnRate: rate }));
          expect(result.tachometer.urgency).toBe("amber");
        },
      ),
    );
  });

  it("is red when burnRate >= 500", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 500, max: 2000 }),
        (rate) => {
          const result = computeGaugeClusterData(createSnapshot({ burnRate: rate }));
          expect(result.tachometer.urgency).toBe("red");
        },
      ),
    );
  });
});

// ---------------------------------------------------------------------------
// Value passthrough properties
// ---------------------------------------------------------------------------

describe("Gauge values are passed through from metrics", () => {
  it("all numeric gauge values are non-negative", () => {
    fc.assert(
      fc.property(sessionMetricsArb, (metrics) => {
        const result = computeGaugeClusterData(metrics);
        expect(result.tachometer.value).toBeGreaterThanOrEqual(0);
        expect(result.fuelGauge.value).toBeGreaterThanOrEqual(0);
        expect(result.odometer.value).toBeGreaterThanOrEqual(0);
        expect(result.rpmCounter.value).toBeGreaterThanOrEqual(0);
      }),
    );
  });

  it("passes burnRate to tachometer value", () => {
    const result = computeGaugeClusterData(createSnapshot({ burnRate: 250 }));
    expect(result.tachometer.value).toBe(250);
  });

  it("passes contextWindowPct to fuel gauge value", () => {
    const result = computeGaugeClusterData(createSnapshot({ contextWindowPct: 45 }));
    expect(result.fuelGauge.value).toBe(45);
  });

  it("passes sessionCost to odometer value", () => {
    const result = computeGaugeClusterData(createSnapshot({ sessionCost: 1.23 }));
    expect(result.odometer.value).toBeCloseTo(1.23);
  });

  it("passes activeAgentCount to rpmCounter value", () => {
    const result = computeGaugeClusterData(createSnapshot({ activeAgentCount: 3 }));
    expect(result.rpmCounter.value).toBe(3);
  });
});

// ---------------------------------------------------------------------------
// Warning cluster
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// Fuel gauge token label
// ---------------------------------------------------------------------------

describe("Fuel gauge token label", () => {
  it("shows 'Xk / Yk tokens' when maxTokens > 0", () => {
    const label = formatContextTokenLabel(50000, 200000);
    expect(label).toBe("50k / 200k tokens");
  });

  it("is empty when maxTokens is 0", () => {
    const label = formatContextTokenLabel(50000, 0);
    expect(label).toBe("");
  });

  it("rounds to nearest thousand", () => {
    const label = formatContextTokenLabel(50500, 199500);
    expect(label).toBe("51k / 200k tokens");
  });

  it("fuel gauge data includes tokenLabel from metrics", () => {
    const result = computeGaugeClusterData(createSnapshot({
      contextWindowPct: 45,
      contextWindowTokens: 90000,
      contextWindowMaxTokens: 200000,
    }));
    expect(result.fuelGauge.tokenLabel).toBe("90k / 200k tokens");
  });

  it("fuel gauge tokenLabel is empty when max is unknown", () => {
    const result = computeGaugeClusterData(createSnapshot({
      contextWindowPct: 45,
      contextWindowTokens: 0,
      contextWindowMaxTokens: 0,
    }));
    expect(result.fuelGauge.tokenLabel).toBe("");
  });
});

// ---------------------------------------------------------------------------
// Warning cluster
// ---------------------------------------------------------------------------

describe("Warning cluster hook health", () => {
  it("reports normal when hookEventCount > 0 (events flowing)", () => {
    const result = computeGaugeClusterData(createSnapshot({ hookEventCount: 50 }));
    expect(result.warningCluster.hookHealth).toBe("normal");
  });

  it("reports degraded when hookEventCount is 0 (no events received)", () => {
    const result = computeGaugeClusterData(createSnapshot({ hookEventCount: 0 }));
    expect(result.warningCluster.hookHealth).toBe("degraded");
  });
});

/**
 * Unit tests: Burn Rate Calculator (Step 02-01)
 *
 * Pure function: (events: Array<{timestamp, tokens}>, windowSeconds) => number
 *
 * Properties tested:
 * - Empty array returns 0
 * - Events outside window return 0
 * - Single event within window returns tokens / windowSeconds
 * - Result is always non-negative
 * - More tokens in window means higher or equal burn rate
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import { calculateBurnRate } from "../../../../../src/plugins/norbert-usage/domain/burnRate";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const tokenEventArb = fc.record({
  timestamp: fc.integer({ min: 1_000_000_000, max: 2_000_000_000 }),
  tokens: fc.nat({ max: 100_000 }),
});

const windowSecondsArb = fc.integer({ min: 1, max: 3600 });

// ---------------------------------------------------------------------------
// Empty input
// ---------------------------------------------------------------------------

describe("calculateBurnRate with empty events", () => {
  it("returns 0 for empty array", () => {
    fc.assert(
      fc.property(windowSecondsArb, (window) => {
        expect(calculateBurnRate([], window)).toBe(0);
      }),
    );
  });
});

// ---------------------------------------------------------------------------
// Events outside window
// ---------------------------------------------------------------------------

describe("calculateBurnRate with all events outside window", () => {
  it("returns 0 when all events are before the window", () => {
    const now = 1_700_000_000;
    const windowSeconds = 60;
    const oldEvents = [
      { timestamp: now - 120, tokens: 500 },
      { timestamp: now - 180, tokens: 300 },
    ];
    expect(calculateBurnRate(oldEvents, windowSeconds, now)).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Single event within window
// ---------------------------------------------------------------------------

describe("calculateBurnRate with single event in window", () => {
  it("returns tokens divided by window seconds", () => {
    const now = 1_700_000_000;
    const windowSeconds = 60;
    const events = [{ timestamp: now - 10, tokens: 600 }];
    expect(calculateBurnRate(events, windowSeconds, now)).toBeCloseTo(600 / 60, 5);
  });
});

// ---------------------------------------------------------------------------
// Multiple events, some in window
// ---------------------------------------------------------------------------

describe("calculateBurnRate with mixed events", () => {
  it("only counts tokens from events within the window", () => {
    const now = 1_700_000_000;
    const windowSeconds = 60;
    const events = [
      { timestamp: now - 10, tokens: 400 },   // in window
      { timestamp: now - 30, tokens: 200 },   // in window
      { timestamp: now - 120, tokens: 9999 }, // outside window
    ];
    expect(calculateBurnRate(events, windowSeconds, now)).toBeCloseTo(600 / 60, 5);
  });
});

// ---------------------------------------------------------------------------
// Property: result is always non-negative
// ---------------------------------------------------------------------------

describe("burn rate is always non-negative", () => {
  it("for any events and window, result >= 0", () => {
    fc.assert(
      fc.property(
        fc.array(tokenEventArb, { maxLength: 50 }),
        windowSecondsArb,
        (events, window) => {
          const result = calculateBurnRate(events, window);
          expect(result).toBeGreaterThanOrEqual(0);
        },
      ),
    );
  });
});

// ---------------------------------------------------------------------------
// Property: more tokens in window => higher or equal burn rate
// ---------------------------------------------------------------------------

describe("adding tokens to window increases burn rate", () => {
  it("adding an event within window produces >= burn rate", () => {
    fc.assert(
      fc.property(
        fc.array(tokenEventArb, { maxLength: 10 }),
        windowSecondsArb,
        fc.nat({ max: 100_000 }),
        (events, window, extraTokens) => {
          const now = 2_000_000_000;
          const baseBurnRate = calculateBurnRate(events, window, now);
          const augmented = [...events, { timestamp: now - 1, tokens: extraTokens }];
          const newBurnRate = calculateBurnRate(augmented, window, now);
          expect(newBurnRate).toBeGreaterThanOrEqual(baseBurnRate);
        },
      ),
    );
  });
});

/**
 * Unit tests for computeDashboardData.
 *
 * Pure domain function: SessionMetrics => DashboardData
 * Tests cover formatting, urgency thresholds, onboarding detection,
 * and daily cost aggregation.
 */

import { describe, it, expect } from "vitest";
import {
  computeDashboardData,
  deriveSessionLabel,
  type DashboardData,
} from "../../../../../src/plugins/norbert-usage/domain/dashboard";
import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../../../src/plugins/norbert-usage/domain/metricsAggregator";

// ---------------------------------------------------------------------------
// Helper
// ---------------------------------------------------------------------------

const createMetrics = (overrides: Partial<SessionMetrics> = {}): SessionMetrics => ({
  ...createInitialMetrics("unit-test"),
  ...overrides,
});

// ---------------------------------------------------------------------------
// Running Cost card
// ---------------------------------------------------------------------------

describe("Running Cost card formatting", () => {
  it("formats cost to two decimal places with dollar sign", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionCost: 1.5 }));
    expect(dashboard.runningCost.label).toBe("Running Cost");
    expect(dashboard.runningCost.value).toBe("$1.50");
  });

  it("formats zero cost as $0.00", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionCost: 0 }));
    expect(dashboard.runningCost.value).toBe("$0.00");
  });

  it("formats large cost with two decimals", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionCost: 123.456 }));
    expect(dashboard.runningCost.value).toBe("$123.46");
  });
});

// ---------------------------------------------------------------------------
// Token Count card
// ---------------------------------------------------------------------------

describe("Token Count card formatting", () => {
  it("formats total tokens with comma separator", () => {
    const dashboard = computeDashboardData(
      createMetrics({ totalTokens: 112400, inputTokens: 62000, outputTokens: 50400 }),
    );
    expect(dashboard.tokenCount.label).toBe("Token Count");
    expect(dashboard.tokenCount.value).toBe("112,400");
  });

  it("shows input/output breakdown in subtitle as Xk in / Xk out", () => {
    const dashboard = computeDashboardData(
      createMetrics({ totalTokens: 112400, inputTokens: 62000, outputTokens: 50400 }),
    );
    expect(dashboard.tokenCount.subtitle).toContain("62k in");
    expect(dashboard.tokenCount.subtitle).toContain("50k out");
  });

  it("formats zero tokens as 0", () => {
    const dashboard = computeDashboardData(createMetrics({ totalTokens: 0 }));
    expect(dashboard.tokenCount.value).toBe("0");
  });
});

// ---------------------------------------------------------------------------
// Active Agents card
// ---------------------------------------------------------------------------

describe("Active Agents card", () => {
  it("shows agent count as string", () => {
    const dashboard = computeDashboardData(createMetrics({ activeAgentCount: 3 }));
    expect(dashboard.activeAgents.label).toBe("Active Agents");
    expect(dashboard.activeAgents.value).toBe("3");
  });
});

// ---------------------------------------------------------------------------
// Tool Calls card
// ---------------------------------------------------------------------------

describe("Tool Calls card", () => {
  it("shows tool call count as string", () => {
    const dashboard = computeDashboardData(createMetrics({ toolCallCount: 42 }));
    expect(dashboard.toolCalls.label).toBe("Tool Calls");
    expect(dashboard.toolCalls.value).toBe("42");
  });
});

// ---------------------------------------------------------------------------
// Context Window card with urgency thresholds
// ---------------------------------------------------------------------------

describe("Context Window card urgency", () => {
  it("shows normal urgency below 70%", () => {
    const dashboard = computeDashboardData(createMetrics({ contextWindowPct: 50 }));
    expect(dashboard.contextWindow.label).toBe("Context Window");
    expect(dashboard.contextWindow.value).toBe("50%");
    expect(dashboard.contextWindow.urgency).toBe("normal");
  });

  it("shows amber urgency at 70%", () => {
    const dashboard = computeDashboardData(createMetrics({ contextWindowPct: 70 }));
    expect(dashboard.contextWindow.urgency).toBe("amber");
  });

  it("shows amber urgency at 89%", () => {
    const dashboard = computeDashboardData(createMetrics({ contextWindowPct: 89 }));
    expect(dashboard.contextWindow.urgency).toBe("amber");
  });

  it("shows red urgency at 90%", () => {
    const dashboard = computeDashboardData(createMetrics({ contextWindowPct: 90 }));
    expect(dashboard.contextWindow.urgency).toBe("red");
  });

  it("shows red urgency at 100%", () => {
    const dashboard = computeDashboardData(createMetrics({ contextWindowPct: 100 }));
    expect(dashboard.contextWindow.urgency).toBe("red");
  });
});

// ---------------------------------------------------------------------------
// Hook Health card
// ---------------------------------------------------------------------------

describe("Hook Health card", () => {
  it("shows OK with normal urgency when events are flowing", () => {
    const dashboard = computeDashboardData(createMetrics({ hookEventCount: 200 }));
    expect(dashboard.hookHealth.label).toBe("Hook Health");
    expect(dashboard.hookHealth.value).toBe("OK");
    expect(dashboard.hookHealth.urgency).toBe("normal");
    expect(dashboard.hookHealth.subtitle).toBe("200 events");
  });

  it("shows 'No Events' with amber urgency when hookEventCount is 0", () => {
    const dashboard = computeDashboardData(createMetrics({ hookEventCount: 0 }));
    expect(dashboard.hookHealth.value).toBe("No Events");
    expect(dashboard.hookHealth.urgency).toBe("amber");
    expect(dashboard.hookHealth.subtitle).toBe("");
  });
});

// ---------------------------------------------------------------------------
// Onboarding detection
// ---------------------------------------------------------------------------

describe("Onboarding detection", () => {
  it("isOnboarding is true when all metrics are zero", () => {
    const dashboard = computeDashboardData(createInitialMetrics("empty"));
    expect(dashboard.isOnboarding).toBe(true);
  });

  it("isOnboarding is false when session has activity", () => {
    const dashboard = computeDashboardData(
      createMetrics({ sessionId: "active", sessionCost: 1, totalTokens: 100 }),
    );
    expect(dashboard.isOnboarding).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Session label
// ---------------------------------------------------------------------------

describe("Session label", () => {
  it("contains session ID when non-default", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionId: "refactor-auth" }));
    expect(dashboard.sessionLabel).toBe("refactor-auth");
  });

  it("is empty for 'default' session ID", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionId: "default" }));
    expect(dashboard.sessionLabel).toBe("");
  });

  it("is empty for empty session ID", () => {
    const dashboard = computeDashboardData(createMetrics({ sessionId: "" }));
    expect(dashboard.sessionLabel).toBe("");
  });

  it("truncates long IDs with ellipsis", () => {
    const longId = "this-is-a-very-long-session-identifier-that-should-be-truncated";
    const label = deriveSessionLabel(longId);
    expect(label).toHaveLength(20);
    expect(label).toMatch(/\.\.\.$/);
  });

  it("passes through IDs of 20 chars or less", () => {
    const label = deriveSessionLabel("exactly-20-chars!!!!"); // 20 chars
    expect(label).toBe("exactly-20-chars!!!!");
  });
});

