/**
 * Unit tests: metricsStore adapter (Step 03-03)
 *
 * The metricsStore is the ONLY mutable cell in the norbert-usage plugin.
 * It holds current SessionMetrics + TimeSeriesBuffer, notifies subscribers
 * on state change, and returns unsubscribe functions.
 *
 * Behaviors tested:
 * - Initial state returns zeroed metrics for given session ID
 * - getMetrics/getTimeSeries return current state
 * - update() replaces state and notifies all subscribers
 * - subscribe() returns unsubscribe function that stops notifications
 * - Multiple subscribers all receive updates
 * - Unsubscribed callback is not called on subsequent updates
 */

import { describe, it, expect } from "vitest";
import { createMetricsStore } from "../../../../../src/plugins/norbert-usage/adapters/metricsStore";
import { createInitialMetrics } from "../../../../../src/plugins/norbert-usage/domain/metricsAggregator";
import { createBuffer } from "../../../../../src/plugins/norbert-usage/domain/timeSeriesSampler";
import type { SessionMetrics, TimeSeriesBuffer } from "../../../../../src/plugins/norbert-usage/domain/types";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const makeMetrics = (overrides: Partial<SessionMetrics> = {}): SessionMetrics => ({
  ...createInitialMetrics("test-session"),
  ...overrides,
});

const makeTimeSeries = (capacity = 60): TimeSeriesBuffer =>
  createBuffer(capacity);

// ---------------------------------------------------------------------------
// Initial state
// ---------------------------------------------------------------------------

describe("metricsStore initial state", () => {
  it("returns zeroed metrics with provided session ID", () => {
    const store = createMetricsStore("my-session");
    const metrics = store.getMetrics();

    expect(metrics.sessionId).toBe("my-session");
    expect(metrics.totalTokens).toBe(0);
    expect(metrics.sessionCost).toBe(0);
    expect(metrics.hookEventCount).toBe(0);
  });

  it("returns empty time series buffer", () => {
    const store = createMetricsStore("my-session");
    const timeSeries = store.getTimeSeries();

    expect(timeSeries.samples).toEqual([]);
    expect(timeSeries.capacity).toBeGreaterThan(0);
  });

  it("uses default session ID when none provided", () => {
    const store = createMetricsStore();
    const metrics = store.getMetrics();

    expect(metrics.sessionId).toBeTruthy();
  });
});

// ---------------------------------------------------------------------------
// update() replaces state and notifies subscribers
// ---------------------------------------------------------------------------

describe("metricsStore update", () => {
  it("replaces metrics state accessible via getMetrics", () => {
    const store = createMetricsStore("s1");
    const updated = makeMetrics({ sessionId: "s1", totalTokens: 500, sessionCost: 1.5 });
    const timeSeries = makeTimeSeries();

    store.update(updated, timeSeries);

    expect(store.getMetrics().totalTokens).toBe(500);
    expect(store.getMetrics().sessionCost).toBe(1.5);
  });

  it("replaces time series state accessible via getTimeSeries", () => {
    const store = createMetricsStore("s1");
    const metrics = makeMetrics({ sessionId: "s1" });
    const timeSeries: TimeSeriesBuffer = {
      samples: [{ timestamp: 1000, tokenRate: 10, costRate: 0.01 }],
      capacity: 60,
      headIndex: 0,
    };

    store.update(metrics, timeSeries);

    expect(store.getTimeSeries().samples).toHaveLength(1);
    expect(store.getTimeSeries().samples[0].tokenRate).toBe(10);
  });

  it("notifies subscriber with new metrics and time series", () => {
    const store = createMetricsStore("s1");
    const received: Array<{ metrics: SessionMetrics; timeSeries: TimeSeriesBuffer }> = [];

    store.subscribe((metrics, timeSeries) => {
      received.push({ metrics, timeSeries });
    });

    const updated = makeMetrics({ sessionId: "s1", totalTokens: 100 });
    const timeSeries = makeTimeSeries();
    store.update(updated, timeSeries);

    expect(received).toHaveLength(1);
    expect(received[0].metrics.totalTokens).toBe(100);
  });

  it("notifies all subscribers on each update", () => {
    const store = createMetricsStore("s1");
    let callCountA = 0;
    let callCountB = 0;

    store.subscribe(() => { callCountA += 1; });
    store.subscribe(() => { callCountB += 1; });

    store.update(makeMetrics(), makeTimeSeries());

    expect(callCountA).toBe(1);
    expect(callCountB).toBe(1);
  });
});

// ---------------------------------------------------------------------------
// subscribe() returns unsubscribe function
// ---------------------------------------------------------------------------

describe("metricsStore subscribe/unsubscribe", () => {
  it("returns a function that stops notifications", () => {
    const store = createMetricsStore("s1");
    let callCount = 0;

    const unsubscribe = store.subscribe(() => { callCount += 1; });

    store.update(makeMetrics(), makeTimeSeries());
    expect(callCount).toBe(1);

    unsubscribe();

    store.update(makeMetrics(), makeTimeSeries());
    expect(callCount).toBe(1); // not called again
  });

  it("does not affect other subscribers when one unsubscribes", () => {
    const store = createMetricsStore("s1");
    let callCountA = 0;
    let callCountB = 0;

    const unsubA = store.subscribe(() => { callCountA += 1; });
    store.subscribe(() => { callCountB += 1; });

    store.update(makeMetrics(), makeTimeSeries());
    expect(callCountA).toBe(1);
    expect(callCountB).toBe(1);

    unsubA();

    store.update(makeMetrics(), makeTimeSeries());
    expect(callCountA).toBe(1); // stopped
    expect(callCountB).toBe(2); // still receiving
  });
});

tests/unit/plugins/norbert-usage/event-p.source:
/**
 * Integration test: Event Pipeline (DB event → hookProcessor → metricsStore)
 *
 * This test exercises the full frontend event pipeline using production-shaped
 * event payloads (as returned by Tauri IPC `get_session_events`).
 *
 * The bug this catches: hookProcessor received the full DB event wrapper
 * { session_id, event_type, payload: { usage: {...} }, ... } but passed it
 * as-is to the aggregator. The token extractor looked for `payload.usage`
 * at the wrong nesting level and always returned "absent".
 *
 * This test wires up the real plugin onLoad, feeds production-shaped events
 * through the registered hook processor, and asserts the metrics store
 * reflects extracted tokens and computed costs.
 *
 * NOTE: usageMetricsStore is a module-level singleton that accumulates state
 * across tests. Tests use delta assertions (before/after) instead of absolute
 * values.
 */

import { describe, it, expect, beforeAll } from "vitest";
import { usageMetricsStore } from "../../../../src/plugins/norbert-usage/index";
import { norbertUsagePlugin } from "../../../../src/plugins/norbert-usage/index";
import { resetHookBridge, deliverHookEvent } from "../../../../src/plugins/hookBridge";
import { createPluginRegistry } from "../../../../src/plugins/pluginRegistry";
import { createNorbertAPI } from "../../../../src/plugins/apiFactory";
import { loadPlugins } from "../../../../src/plugins/lifecycleManager";
import { norbertSessionPlugin } from "../../../../src/plugins/norbert-session/index";

// ---------------------------------------------------------------------------
// Production event shapes — exactly what get_session_events returns via IPC
// ---------------------------------------------------------------------------

/** A PostToolUse event WITH token usage (tool_call_end in canonical form). */
const makeWrappedToolCallEndWithUsage = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_call_end",
  payload: {
    session_id: sessionId,
    tool: "Read",
    input: { file_path: "/tmp/test.ts" },
    usage: {
      input_tokens: 1200,
      output_tokens: 400,
      cache_read_input_tokens: 500,
      cache_creation_input_tokens: 0,
      model: "claude-sonnet-4-20250514",
    },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "claude_code",
});

/** A SessionStart event (no token data expected). */
const makeWrappedSessionStart = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "session_start",
  payload: {
    session_id: sessionId,
  },
  received_at: "2026-03-13T21:59:00Z",
  provider: "claude_code",
});

/** A PreToolUse event (tool_call_start, no token data). */
const makeWrappedToolCallStart = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_call_start",
  payload: {
    session_id: sessionId,
    tool: "Read",
    input: { file_path: "/tmp/test.ts" },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "claude_code",
});

/** A UserPromptSubmit event WITH token usage (prompt_submit). */
const makeWrappedPromptSubmit = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "prompt_submit",
  payload: {
    session_id: sessionId,
    usage: {
      input_tokens: 3000,
      output_tokens: 1500,
      cache_read_input_tokens: 0,
      cache_creation_input_tokens: 0,
      model: "claude-opus-4-20250514",
    },
  },
  received_at: "2026-03-13T22:01:00Z",
  provider: "claude_code",
});

// ---------------------------------------------------------------------------
// Integration tests
// ---------------------------------------------------------------------------

describe("Event pipeline integration: DB event → hookBridge → metricsStore", () => {
  beforeAll(() => {
    // Initialize plugin system once (same as App.tsx does on mount)
    resetHookBridge();
    loadPlugins(
      [norbertSessionPlugin, norbertUsagePlugin],
      createPluginRegistry(),
      createNorbertAPI,
    );
  });

  it("tool_call_end with usage data produces non-zero tokens and cost in the store", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedToolCallEndWithUsage("sess-integration-1");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    const deltaTokens = after.totalTokens - before.totalTokens;
    expect(deltaTokens).toBe(1600); // 1200 input + 400 output
    expect(after.inputTokens - before.inputTokens).toBe(1200);
    expect(after.outputTokens - before.outputTokens).toBe(400);
    expect(after.sessionCost).toBeGreaterThan(before.sessionCost);
    expect(after.hookEventCount).toBeGreaterThan(before.hookEventCount);
  });

  it("session_start event increments activeAgentCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedSessionStart("sess-integration-2");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.activeAgentCount).toBe(before.activeAgentCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
    expect(after.sessionCost).toBe(before.sessionCost); // no change
    expect(after.hookEventCount).toBe(before.hookEventCount + 1);
  });

  it("tool_call_start increments toolCallCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedToolCallStart("sess-integration-3");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.toolCallCount).toBe(before.toolCallCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
  });

  it("prompt_submit with usage data adds tokens and cost", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedPromptSubmit("sess-integration-4");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.totalTokens - before.totalTokens).toBe(4500); // 3000 + 1500
    expect(after.inputTokens - before.inputTokens).toBe(3000);
    expect(after.outputTokens - before.outputTokens).toBe(1500);
    expect(after.sessionCost).toBeGreaterThan(before.sessionCost);
  });

  it("time series buffer receives samples when token events flow", () => {
    const timeSeries = usageMetricsStore.getTimeSeries();
    // Previous token-bearing events should have pushed samples
    expect(timeSeries.samples.length).toBeGreaterThanOrEqual(1);
    expect(timeSeries.samples[0].tokenRate).toBeGreaterThan(0);
  });
});

tests/acceptance/norbert-usage/gauge-clu.source:
/**
 * Acceptance tests: Gauge Cluster Dashboard View (US-003)
 *
 * Validates that the Gauge Cluster computes correct metric card data
 * from SessionMetrics, including urgency zone transitions for fuel
 * gauge and tachometer.
 *
 * Driving ports: pure domain functions (metrics -> gauge card data)
 * These tests exercise the data transformation that feeds the 5-card
 * gauge cluster, not the React rendering.
 *
 * Traces to: US-003 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  createInitialMetrics,
  type SessionMetrics,
} from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import {
  computeGaugeClusterData,
  type GaugeClusterData,
} from "../../../src/plugins/norbert-usage/domain/gaugeCluster";

// ---------------------------------------------------------------------------
// Helper: create metrics snapshot with specific values
// ---------------------------------------------------------------------------

const createMetricsSnapshot = (overrides: Partial<SessionMetrics> = {}): SessionMetrics => ({
  ...createInitialMetrics("test-session"),
  sessionId: "refactor-auth",
  sessionStartedAt: "2025-01-01T00:00:00Z",
  ...overrides,
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Gauge Cluster Data Computation
// ---------------------------------------------------------------------------

describe("Gauge Cluster displays all instrument data for active session", () => {
  it("computes tachometer, fuel gauge, odometer, RPM, warning, and clock values", () => {
    // Given an active session with known metrics:
    // 150 tok/s burn rate, 25% context, $0.83 cost, 1 agent, healthy hooks, 12m 30s elapsed
    const metrics = createMetricsSnapshot({
      burnRate: 150,
      contextWindowPct: 25,
      sessionCost: 0.83,
      activeAgentCount: 1,
      hookEventCount: 50,
      lastEventAt: "2025-01-01T00:12:30Z",
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then the tachometer shows 150 tok/s
    expect(gaugeData.tachometer.value).toBe(150);
    expect(gaugeData.tachometer.urgency).toBe("normal");

    // And the fuel gauge shows 25% in normal zone
    expect(gaugeData.fuelGauge.value).toBe(25);
    expect(gaugeData.fuelGauge.urgency).toBe("normal");

    // And the odometer shows $0.83
    expect(gaugeData.odometer.value).toBeCloseTo(0.83);

    // And the RPM counter shows 1 agent
    expect(gaugeData.rpmCounter.value).toBe(1);

    // And the warning cluster shows normal status
    expect(gaugeData.warningCluster.hookHealth).toBe("normal");
  });
});

describe("Fuel gauge transitions to amber at 70% context utilization", () => {
  it("context at 70% triggers amber urgency zone", () => {
    // Given a session with context utilization climbing
    const metrics = createMetricsSnapshot({
      contextWindowPct: 70,
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then the fuel gauge is in the amber zone
    expect(gaugeData.fuelGauge.urgency).toBe("amber");
  });
});

describe("Fuel gauge transitions to red at 90% context utilization", () => {
  it("context at 90% triggers red urgency zone", () => {
    // Given a session with context utilization at 90%
    const metrics = createMetricsSnapshot({
      contextWindowPct: 90,
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then the fuel gauge is in the red zone
    expect(gaugeData.fuelGauge.urgency).toBe("red");
  });
});

describe("Tachometer enters redline at sustained high burn rate", () => {
  it("burn rate above redline threshold triggers red urgency", () => {
    // Given a session with token burn rate at 520 tok/s
    // (above the default redline threshold)
    const metrics = createMetricsSnapshot({
      burnRate: 520,
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then the tachometer is in the redline zone
    expect(gaugeData.tachometer.urgency).toBe("red");
  });
});

describe("Fuel gauge displays both percentage and token count for active session", () => {
  it("shows token label when context window token counts are known", () => {
    // Given a session with known context usage in tokens
    const metrics = createMetricsSnapshot({
      contextWindowPct: 45,
      contextWindowTokens: 90000,
      contextWindowMaxTokens: 200000,
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then the fuel gauge shows percentage
    expect(gaugeData.fuelGauge.value).toBe(45);

    // And the token label shows current/max
    expect(gaugeData.fuelGauge.tokenLabel).toBe("90k / 200k tokens");
  });

  it("omits token label when max is unknown", () => {
    // Given a session where context token counts are unavailable
    const metrics = createMetricsSnapshot({
      contextWindowPct: 45,
      contextWindowTokens: 0,
      contextWindowMaxTokens: 0,
    });

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then no token label is shown
    expect(gaugeData.fuelGauge.tokenLabel).toBe("");
  });
});

describe("Gauge Cluster handles zero metrics for idle session", () => {
  it("all instruments show zero or default values when no events received", () => {
    // Given a newly started session with no events yet
    const metrics = createInitialMetrics("idle-session");

    // When gauge cluster data is computed
    const gaugeData = computeGaugeClusterData(metrics);

    // Then all instruments show safe default values
    expect(gaugeData.tachometer.value).toBe(0);
    expect(gaugeData.fuelGauge.value).toBe(0);
    expect(gaugeData.fuelGauge.urgency).toBe("normal");
    expect(gaugeData.odometer.value).toBe(0);
    expect(gaugeData.rpmCounter.value).toBe(0);
  });
});

tests/acceptance/norbert-usage/plugin-re.source:
/**
 * Acceptance tests: norbert-usage Plugin Registration and Lifecycle (US-001)
 *
 * Validates that norbert-usage registers its views, tab, status item,
 * and hook processor via the NorbertPlugin API during onLoad, and
 * cleans up during onUnload.
 *
 * Driving ports: loadPlugins, createPluginRegistry, createNorbertAPI
 * Domain: plugin entry point (NorbertPlugin interface)
 *
 * Traces to: US-001 acceptance criteria
 */

import { describe, it, expect, beforeEach } from "vitest";
import { loadPlugins } from "../../../src/plugins/lifecycleManager";
import { createNorbertAPI } from "../../../src/plugins/apiFactory";
import {
  createPluginRegistry,
  getViewsByPlugin,
  getTabsByPlugin,
  getStatusItemsByPlugin,
  getHookRegistrationsByPlugin,
} from "../../../src/plugins/pluginRegistry";
import { resetHookBridge } from "../../../src/plugins/hookBridge";
import { norbertUsagePlugin } from "../../../src/plugins/norbert-usage/index";

beforeEach(() => {
  resetHookBridge();
});

const loadUsagePlugin = () =>
  loadPlugins(
    [norbertUsagePlugin],
    createPluginRegistry(),
    createNorbertAPI
  );

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

// @walking_skeleton
describe("User sees Usage tab after norbert-usage loads", () => {
  it("plugin registers views, tab, status item, and hook processor on load", () => {
    // Given the norbert-usage plugin implements the NorbertPlugin interface
    // And the manifest declares id "norbert-usage" with no plugin dependencies
    expect(norbertUsagePlugin.manifest.id).toBe("norbert-usage");
    expect(norbertUsagePlugin.manifest.dependencies).toEqual({});

    // When the plugin system loads norbert-usage
    const registry = loadUsagePlugin();

    // Then the plugin is loaded successfully
    expect(registry.loadedPluginIds).toContain("norbert-usage");

    // And 3 views are registered: gauge-cluster, oscilloscope, usage-dashboard
    const views = getViewsByPlugin(registry, "norbert-usage");
    expect(views).toHaveLength(3);
    const viewIds = views.map((v) => v.id);
    expect(viewIds).toContain("gauge-cluster");
    expect(viewIds).toContain("oscilloscope");
    expect(viewIds).toContain("usage-dashboard");

    // And a sidebar tab "usage" is registered
    const tabs = getTabsByPlugin(registry, "norbert-usage");
    expect(tabs).toHaveLength(1);
    expect(tabs[0].id).toBe("usage");
    expect(tabs[0].label).toBe("Usage");

    // And a status bar item "cost-ticker" is registered on the right
    const statusItems = getStatusItemsByPlugin(registry, "norbert-usage");
    expect(statusItems).toHaveLength(1);
    expect(statusItems[0].id).toBe("cost-ticker");
    expect(statusItems[0].position).toBe("right");

    // And a hook processor is registered for session events
    const hooks = getHookRegistrationsByPlugin(registry, "norbert-usage");
    expect(hooks.length).toBeGreaterThanOrEqual(1);
    expect(hooks.some((h) => h.hookName === "session-event")).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: View Registration Details
// ---------------------------------------------------------------------------

describe("Gauge Cluster view supports floating panel mode", () => {
  it("registers with floatMetric for session cost pill display", () => {
    // Given norbert-usage is loaded
    const registry = loadUsagePlugin();

    // When inspecting the gauge-cluster view registration
    const views = getViewsByPlugin(registry, "norbert-usage");
    const gaugeCluster = views.find((v) => v.id === "gauge-cluster");

    // Then the gauge-cluster view registers with floatMetric "session_cost"
    expect(gaugeCluster).toBeDefined();
    expect(gaugeCluster!.floatMetric).toBe("session_cost");
    // And it is not the primary view
    expect(gaugeCluster!.primaryView).toBe(false);
  });
});

describe("Usage Dashboard is the primary view", () => {
  it("usage-dashboard registers as primaryView for default display", () => {
    // Given norbert-usage is loaded
    const registry = loadUsagePlugin();

    // When inspecting the usage-dashboard view registration
    const views = getViewsByPlugin(registry, "norbert-usage");
    const dashboard = views.find((v) => v.id === "usage-dashboard");

    // Then the usage-dashboard view is marked as primary
    expect(dashboard).toBeDefined();
    expect(dashboard!.primaryView).toBe(true);
    expect(dashboard!.label).toBe("Usage Dashboard");
  });
});

// ---------------------------------------------------------------------------
// ERROR / BOUNDARY SCENARIOS
// ---------------------------------------------------------------------------

describe("Plugin operates with degraded functionality when API unavailable", () => {
  it("continues with views and tab when status item registration fails", () => {
    // Given Norbert core does not support registerStatusItem
    // (simulated by providing a modified API factory that throws on registerStatusItem)

    // When norbert-usage attempts to register all components
    // Then it should not crash -- the plugin should handle partial API availability

    // This test validates the plugin's resilience to partial API support.
    // The plugin should log a warning and continue operating with views and tab
    // even if the status item registration is unavailable.

    // For now, we verify the plugin loads without error through the standard path.
    // The degradation behavior will be tested once the plugin implementation exists.
    const registry = loadUsagePlugin();

    // Then the plugin is loaded
    expect(registry.loadedPluginIds).toContain("norbert-usage");

    // And views are still registered
    const views = getViewsByPlugin(registry, "norbert-usage");
    expect(views.length).toBeGreaterThanOrEqual(3);
  });
});

describe("Plugin uses only public NorbertPlugin API", () => {
  it("norbert-usage imports no internal Norbert modules", () => {
    // Given norbert-usage source code exists
    // When inspecting its imports
    // Then it imports only from ../types (plugin types) and its own domain modules

    // This is a structural test that verifies hexagonal boundary compliance.
    // The plugin must not import from pluginLoader, lifecycleManager, apiFactory,
    // sandboxEnforcer, hookBridge, pluginRegistry, or dependencyResolver.
    const fs = require("fs");
    const path = require("path");
    const pluginDir = path.resolve(
      __dirname,
      "../../../src/plugins/norbert-usage"
    );
    const pluginFiles = fs
      .readdirSync(pluginDir)
      .filter((f: string) => f.endsWith(".ts") || f.endsWith(".tsx"));

    for (const file of pluginFiles) {
      const content = fs.readFileSync(
        path.join(pluginDir, file),
        "utf-8"
      );
      const importLines = content.match(/^import .+ from .+$/gm) ?? [];
      for (const importLine of importLines) {
        const importPathMatch = importLine.match(/from\s+["'](.+?)["']/);
        if (importPathMatch) {
          const importPath = importPathMatch[1];
          expect(importPath).not.toContain("@tauri-apps");
          expect(importPath).not.toMatch(
            /\.\.\/(pluginLoader|lifecycleManager|apiFactory|sandboxEnforcer|hookBridge|pluginRegistry|dependencyResolver)/
          );
        }
      }
    }
  });
});

